import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { Workspace } from '../../models/workspace.models';

@Component({
  selector: 'app-workspace-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './workspace-list.component.html',
  styleUrl: './workspace-list.component.css',
})
export class WorkspaceListComponent {
  // DATA CONTRACT: backend-provided list. mockup_cleaner empties this;
  // service_agent wires it to WorkspaceService.list() in ngOnInit().
  workspaces = signal<Workspace[]>([
    { id: 'ws-1', ownerId: 'u1', name: 'Sample Project', createdAt: '2026-06-01T10:00:00Z', updatedAt: '2026-07-10T14:22:00Z', fileCount: 3 },
    { id: 'ws-2', ownerId: 'u1', name: 'API Playground', createdAt: '2026-06-14T09:12:00Z', updatedAt: '2026-07-08T18:05:00Z', fileCount: 12 },
    { id: 'ws-3', ownerId: 'u1', name: 'Marketing Site', createdAt: '2026-05-20T11:40:00Z', updatedAt: '2026-06-30T08:30:00Z', fileCount: 7 },
  ]);

  // UI state
  showCreate = signal(false);
  newName = '';
  renamingId = signal<string | null>(null);
  renameValue = '';

  constructor(private router: Router) {}

  open(ws: Workspace): void {
    this.router.navigate(['/workspaces', ws.id]);
  }

  openCreate(): void {
    this.newName = '';
    this.showCreate.set(true);
  }

  cancelCreate(): void {
    this.showCreate.set(false);
  }

  createWorkspace(): void {
    const name = this.newName.trim();
    if (!name) return;
    const now = new Date(0).toISOString();
    const ws: Workspace = {
      id: 'ws-new-' + (this.workspaces().length + 1),
      ownerId: 'u1',
      name,
      createdAt: now,
      updatedAt: now,
      fileCount: 0,
    };
    this.workspaces.update((list) => [ws, ...list]);
    this.showCreate.set(false);
  }

  startRename(ws: Workspace, ev: Event): void {
    ev.stopPropagation();
    this.renameValue = ws.name;
    this.renamingId.set(ws.id);
  }

  confirmRename(ws: Workspace, ev: Event): void {
    ev.stopPropagation();
    const name = this.renameValue.trim();
    if (name) {
      this.workspaces.update((list) => list.map((w) => (w.id === ws.id ? { ...w, name } : w)));
    }
    this.renamingId.set(null);
  }

  cancelRename(ev: Event): void {
    ev.stopPropagation();
    this.renamingId.set(null);
  }

  deleteWorkspace(ws: Workspace, ev: Event): void {
    ev.stopPropagation();
    this.workspaces.update((list) => list.filter((w) => w.id !== ws.id));
  }
}
